#include <stdio.h>
#include <string.h>

#define MAXV 1001

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        int A[1005];
        for(int i=0;i<N;i++) scanf("%d", &A[i]);
        int runs = K+1;
        static int dp[1002][MAXV]; // dp[t][v]
        static int best[1002];
        memset(dp, 0, sizeof(dp));
        memset(best, 0, sizeof(best));
        for(int idx=0; idx<N; ++idx){
            int a = A[idx];
            for(int t=runs; t>=1; --t){
                int old = dp[t][a];
                int cand = old + 1; // continue same run
                if(t>1) cand = cand > best[t-1]+1 ? cand : best[t-1]+1;
                else cand = cand > 1 ? cand : 1; // start new subsequence
                if(cand > dp[t][a]) dp[t][a] = cand;
                if(dp[t][a] > best[t]) best[t] = dp[t][a];
            }
        }
        int ans = 0;
        for(int t=1; t<=runs; ++t) if(best[t] > ans) ans = best[t];
        printf("%d\n", ans);
    }
    return 0;
}

