import java.io.*;
import java.util.*;

public class Main {
    static final int MAXV = 1001;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int K = fs.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) A[i] = fs.nextInt();
            int runs = K + 1;
            int[][] dp = new int[runs + 1][MAXV];
            int[] best = new int[runs + 1];
            for (int a : A) {
                for (int t = runs; t >= 1; t--) {
                    int old = dp[t][a];
                    int cand = old + 1; // continue same run
                    if (t > 1) cand = Math.max(cand, best[t - 1] + 1);
                    else cand = Math.max(cand, 1);
                    dp[t][a] = Math.max(dp[t][a], cand);
                    best[t] = Math.max(best[t], dp[t][a]);
                }
            }
            int ans = 0;
            for (int t = 1; t <= runs; t++) ans = Math.max(ans, best[t]);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for Java
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

