import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    MAXV = 1001
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        runs = K + 1
        dp = [[0]*MAXV for _ in range(runs+1)]
        best = [0]*(runs+1)
        for a in A:
            for t in range(runs, 0, -1):
                old = dp[t][a]
                cand = old + 1  # continue same run
                if t > 1:
                    cand = max(cand, best[t-1] + 1)
                else:
                    cand = max(cand, 1)
                if cand > dp[t][a]:
                    dp[t][a] = cand
                if dp[t][a] > best[t]:
                    best[t] = dp[t][a]
        ans = max(best[1:])
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

